using System;

class Program
{
    static void Main(string[] args)
    {
        int number1 = 10;
        int number2 = 3;

        int sum = number1 + number2;
        int difference = number1 - number2;
        int product = number1 * number2;
        int quotient = number1 / number2;
        int remainder = number1 % number2;

        Console.WriteLine($"Toplama: {number1} + {number2} = {sum}");
        Console.WriteLine($"Çıxma: {number1} - {number2} = {difference}");
        Console.WriteLine($"Vurma: {number1} * {number2} = {product}");
        Console.WriteLine($"Bölmə: {number1} / {number2} = {quotient}");
        Console.WriteLine($"Modul: {number1} % {number2} = {remainder}");
    }
}
// Output:
// Toplama: 10 + 3 = 13
// Çıxma: 10 - 3 = 7
// Vurma: 10 * 3 = 30
// Bölmə: 10 / 3 = 3
// Modul: 10 % 3 = 1

using System;

class Program
{
    static void Main(string[] args)
    {
        int a = 5;
        int b = 8;

        bool isEqual = a == b;
        bool isNotEqual = a != b;
        bool isGreater = a > b;
        bool isLess = a < b;
        bool isGreaterOrEqual = a >= b;
        bool isLessOrEqual = a <= b;

        Console.WriteLine($"{a} == {b}: {isEqual}");
        Console.WriteLine($"{a} != {b}: {isNotEqual}");
        Console.WriteLine($"{a} > {b}: {isGreater}");
        Console.WriteLine($"{a} < {b}: {isLess}");
        Console.WriteLine($"{a} >= {b}: {isGreaterOrEqual}");
        Console.WriteLine($"{a} <= {b}: {isLessOrEqual}");
    }
}
// Output:
// 5 == 8: False
// 5 != 8: True
// 5 > 8: False
// 5 < 8: True
// 5 >= 8: False
// 5 <= 8: True

